#include<bits/stdc++.h>
using namespace std;
int n,q,ans;
char a[1010][1010];
int dx[4]={0,-1,0,1};
int dy[4]={1,0,-1,0};
bool vis[1010][1010];
map<char,int> mp;
void dfs(int x,int y)
{
    ans++;
    for(int i=0;i<4;i++)
    {
        int xx=x+dx[i],yy=y+dy[i];
        if(xx<0||xx>n+1||yy<0||yy>n+1||vis[xx][yy])
        {
            continue;
        }
        if(a[xx][yy]=='?'||abs(i-mp[a[xx][yy]])==2)
        {
            vis[xx][yy]=1;
            dfs(xx,yy);
        }
    }
}
int r[200010],c[200010];
int main()
{
    mp['L']=2;
    mp['R']=0;
    mp['U']=1;
    mp['D']=3;
    scanf("%d%d",&n,&q);
    memset(a,'?',sizeof(a));
    for(int i=1;i<=q;i++)
    {
        scanf("%d%d",&r[i],&c[i]);
        cin>>a[r[i]][c[i]];
    }
    vis[0][0]=1;
    dfs(0,0);
    vector<int> res;
    res.push_back((n+2)*(n+2)-ans);
    for(int i=q;i>=2;i--)
    {
        a[r[i]][c[i]]='?';
        if(!vis[r[i]][c[i]])
        {
            int flag=0;
            for(int j=0;j<4;j++)
            {
                int xx=r[i]+dx[j],yy=c[i]+dy[j];
                if(vis[xx][yy])
                {
                    vis[r[i]][c[i]]=1;
                    dfs(r[i],c[i]);
                    break;
                }
            }
        }
        res.push_back((n+2)*(n+2)-ans);
    }
    reverse(res.begin(),res.end());
    for(int i:res)
    {
        printf("%d\n",i);
    }
    return 0;
}
